export type BetaCreateUserProfileRequest = {
  readonly "external_id"?: string
  readonly "name"?: string
  readonly "relationship"?: "external" | "resold" | "internal"
  readonly "metadata"?: { readonly [x: string]: string }
}
export const BetaCreateUserProfileRequest = Schema.Struct({
  "external_id": Schema.optionalKey(
    Schema.String.annotate({
      "description": "Platform's own identifier for this user. Not enforced unique. Maximum 255 characters."
    }).check(Schema.isMinLength(1)).check(Schema.isMaxLength(255))
  ),
  "name": Schema.optionalKey(
    Schema.String.annotate({
      "description":
        "Display name of the entity this profile represents. Required when relationship is `resold` (the resold-to company's name); optional otherwise. Maximum 255 characters."
    }).check(Schema.isMinLength(1)).check(Schema.isMaxLength(255))
  ),
  "relationship": Schema.optionalKey(
    Schema.Literals(["external", "resold", "internal"]).annotate({
      "description":
        "How the entity behind a user profile relates to the platform that owns the API key. `external`: an individual end-user of the platform. `resold`: a company the platform resells Claude access to. `internal`: the platform's own usage."
    })
  ),
  "metadata": Schema.optionalKey(
    Schema.Record(Schema.String, Schema.String).annotate({
      "description":
        "Free-form key-value data to attach to this user profile. Maximum 16 keys, with keys up to 64 characters and values up to 512 characters. Values must be non-empty strings."
    })
  )
})
