export const BetaManagedAgentsMemory = Schema.Struct({
  "type": Schema.Literal("memory"),
  "id": Schema.String.annotate({
    "description":
      "Unique identifier for this memory (a `mem_...` value). Stable across renames; use this ID, not the path, to read, update, or delete the memory."
  }),
  "memory_store_id": Schema.String.annotate({
    "description": "ID of the memory store this memory belongs to (a `memstore_...` value)."
  }),
  "path": Schema.String.annotate({
    "description":
      "Hierarchical path of the memory within the store, e.g. `/projects/foo/notes.md`. Always starts with `/`. Paths are case-sensitive and unique within a store. Maximum 1,024 bytes."
  }),
  "content": Schema.optionalKey(
    Schema.String.annotate({
      "description":
        "The memory's UTF-8 text content. Populated when `view=full`; `null` when `view=basic`. Maximum 100 kB (102,400 bytes)."
    })
  ),
  "content_size_bytes": Schema.Number.annotate({
    "description": "Size of `content` in bytes (the UTF-8 plaintext length). Always populated, regardless of `view`.",
    "format": "int32"
  }).check(Schema.isInt()),
  "content_sha256": Schema.String.annotate({
    "description":
      "Lowercase hex SHA-256 digest of the UTF-8 `content` bytes (64 characters). The server applies no normalization, so clients can compute the same hash locally for staleness checks and as the value for a `content_sha256` precondition on update. Always populated, regardless of `view`."
  }),
  "memory_version_id": Schema.String.annotate({
    "description":
      "ID of the `memory_version` representing this memory's current content (a `memver_...` value). This is the authoritative head pointer; `memory_version` objects do not carry an `is_latest` flag, so compare against this field instead. Enumerate the full history via [List memory versions](/en/api/beta/memory_stores/memory_versions/list)."
  }),
  "created_at": Schema.String.annotate({ "description": "A timestamp in RFC 3339 format", "format": "date-time" }),
  "updated_at": Schema.String.annotate({ "description": "A timestamp in RFC 3339 format", "format": "date-time" })
}).annotate({
  "description":
    "A `memory` object: a single text document at a hierarchical path inside a memory store. The `content` field is populated when `view=full` and `null` when `view=basic`; the `content_size_bytes` and `content_sha256` fields are always populated so sync clients can diff without fetching content. Memories are addressed by their `mem_...` ID; the path is the create key and can be changed via update."
})
