export type RequestContentBlockLocationCitation = {
  readonly "cited_text": string
  readonly "document_index": number
  readonly "document_title": string | null
  readonly "end_block_index": number
  readonly "start_block_index": number
  readonly "type": "content_block_location"
}
export const RequestContentBlockLocationCitation = Schema.Struct({
  "cited_text": Schema.String.annotate({
    "title": "Cited Text",
    "description":
      "The full text of the cited block range, concatenated.\n\nAlways equals the contents of `content[start_block_index:end_block_index]` joined together. The text block is the minimal citable unit; this field is never a substring of a single block. Not counted toward output tokens, and not counted toward input tokens when sent back in subsequent turns."
  }),
  "document_index": Schema.Number.annotate({ "title": "Document Index" }).check(Schema.isInt()).check(
    Schema.isGreaterThanOrEqualTo(0)
  ),
  "document_title": Schema.Union([
    Schema.String.check(Schema.isMinLength(1)).check(Schema.isMaxLength(255)),
    Schema.Null
  ]).annotate({ "title": "Document Title" }),
  "end_block_index": Schema.Number.annotate({
    "title": "End Block Index",
    "description":
      "Exclusive 0-based end index of the cited block range in the source's `content` array.\n\nAlways greater than `start_block_index`; a single-block citation has `end_block_index = start_block_index + 1`."
  }).check(Schema.isInt()),
  "start_block_index": Schema.Number.annotate({
    "title": "Start Block Index",
    "description": "0-based index of the first cited block in the source's `content` array."
  }).check(Schema.isInt()).check(Schema.isGreaterThanOrEqualTo(0)),
  "type": Schema.Literal("content_block_location").annotate({ "title": "Type" })
}).annotate({ "title": "RequestContentBlockLocationCitation" })
